1	import { computed, ref } from 'vue'
2	import { defineStore } from 'pinia'
3	import { fetchMe, login, logout } from '../api/auth'
4	import { ApiClientError, setAuthToken } from '../api/http'
5	import type { AuthUser } from '../types/auth'
6	
7	const TOKEN_KEY = 'vetops.auth.token'
8	
9	function getStorage(): Storage | null {
10	  if (typeof globalThis === 'undefined') {
11	    return null
12	  }
13	
14	  const maybeStorage = (globalThis as { localStorage?: Storage }).localStorage
15	  return maybeStorage ?? null
16	}
17	
18	const storage = getStorage()
19	
20	export const useAuthStore = defineStore('auth', () => {
21	  const token = ref<string>(storage?.getItem(TOKEN_KEY) ?? '')
22	  const user = ref<AuthUser | null>(null)
23	  const loading = ref(false)
24	  const captchaRequired = ref(false)
25	  const sessionExpired = ref(false)
26	
27	  const isAuthenticated = computed(() => token.value !== '' && user.value !== null)
28	
29	  function persistToken(nextToken: string) {
30	    token.value = nextToken
31	    setAuthToken(nextToken)
32	    if (nextToken === '') {
33	      storage?.removeItem(TOKEN_KEY)
34	      return
35	    }
36	    storage?.setItem(TOKEN_KEY, nextToken)
37	  }
38	
39	  async function hydrate(): Promise<void> {
40	    if (token.value === '') {
41	      return
42	    }
43	
44	    setAuthToken(token.value)
45	    try {
46	      const me = await fetchMe()
47	      user.value = me.user
48	      sessionExpired.value = false
49	    } catch {
50	      clearSession()
51	    }
52	  }
53	
54	  async function signIn(username: string, password: string, captchaToken?: string): Promise<void> {
55	    loading.value = true
56	    try {
57	      const result = await login({ username, password, captcha_token: captchaToken })
58	      persistToken(result.token)
59	      captchaRequired.value = result.security.captcha_required
60	      const me = await fetchMe()
61	      user.value = me.user
62	      sessionExpired.value = false
63	      captchaRequired.value = false
64	    } catch (error) {
65	      if (error instanceof ApiClientError && error.code === 'CAPTCHA_REQUIRED') {
66	        captchaRequired.value = true
67	      }
68	      throw error
69	    } finally {
70	      loading.value = false
71	    }
72	  }
73	
74	  async function signOut(): Promise<void> {
75	    try {
76	      if (token.value !== '') {
77	        await logout()
78	      }
79	    } finally {
80	      clearSession()
81	    }
82	  }
83	
84	  function clearSession() {
85	    user.value = null
86	    persistToken('')
87	  }
88	
89	  function markSessionExpired() {
90	    sessionExpired.value = true
91	    clearSession()
92	  }
93	
94	  function hasPermission(permission: string): boolean {
95	    return user.value?.permissions.includes(permission) ?? false
96	  }
97	
98	  function hasAnyRole(roles: string[]): boolean {
99	    if (roles.length === 0) {
100	      return true
101	    }
102	    const roleSet = new Set(user.value?.roles ?? [])
103	    return roles.some((role) => roleSet.has(role as never))
104	  }
105	
106	  return {
107	    token,
108	    user,
109	    loading,
110	    captchaRequired,
111	    sessionExpired,
112	    isAuthenticated,
113	    hydrate,
114	    signIn,
115	    signOut,
116	    markSessionExpired,
117	    hasPermission,
118	    hasAnyRole,
119	  }
120	})
121	

