109	    public function update(Request $request, string $entity, int $id): JsonResponse
110	    {
111	        $table = $this->resolveTable($entity);
112	        if ($table === null) {
113	            return response()->json(ApiResponse::error('NOT_FOUND', 'Unknown entity.', ApiResponse::requestId($request)), 404);
114	        }
115	
116	        $existing = DB::table($table)->where('id', $id)->first();
117	        if ($existing === null) {
118	            return response()->json(ApiResponse::error('NOT_FOUND', 'Record not found.', ApiResponse::requestId($request)), 404);
119	        }
120	
121	        $ifMatch = (int) $request->header('If-Match', (string) ($existing->version ?? 1));
122	        $currentVersion = (int) ($existing->version ?? 1);
123	        if ($this->hasColumn($table, 'version') && $ifMatch !== $currentVersion) {
124	            return response()->json(ApiResponse::error('VERSION_CONFLICT', 'Version mismatch.', ApiResponse::requestId($request)), 409);
125	        }
126	
127	        $payload = $request->all();
128	        $payload['updated_at'] = now()->utc();
129	        if ($this->hasColumn($table, 'version')) {
130	            $payload['version'] = $currentVersion + 1;
131	        }
132	
133	        DB::table($table)->where('id', $id)->update($payload);
134	        $updated = (array) DB::table($table)->where('id', $id)->first();
135	        $this->versioning->snapshot($entity, $id, (int) ($updated['version'] ?? 1), $updated, $request->user()?->id, 'update');
136	
137	        $this->auditLogger->log($request, 'master_data', 'update', 'success', $request->user(), ['entity' => $entity, 'id' => $id]);
138	
139	        return response()->json(['data' => $updated]);
140	    }
