145	            'data' => DB::table('master_versions')
146	                ->where('entity', $entity)
147	                ->where('entity_id', $id)
148	                ->orderByDesc('version')
149	                ->get(),
150	            'request_id' => ApiResponse::requestId($request),
151	        ]);
