154	    public function revert(Request $request, string $entity, int $id): JsonResponse
155	    {
156	        $user = $request->user();
157	        if ($user === null || ! Gate::forUser($user)->allows('permission', 'master.revert')) {
158	            return response()->json(ApiResponse::error('FORBIDDEN', 'Only manager/admin can revert.', ApiResponse::requestId($request)), 403);
159	        }
160	
161	        $table = $this->resolveTable($entity);
162	        if ($table === null) {
163	            return response()->json(ApiResponse::error('NOT_FOUND', 'Unknown entity.', ApiResponse::requestId($request)), 404);
164	        }
165	
166	        $targetVersion = (int) $request->integer('version');
167	        $versionRow = DB::table('master_versions')
168	            ->where('entity', $entity)
169	            ->where('entity_id', $id)
170	            ->where('version', $targetVersion)
171	            ->first();
172	
173	        if ($versionRow === null) {
174	            return response()->json(ApiResponse::error('NOT_FOUND', 'Version not found.', ApiResponse::requestId($request)), 404);
175	        }
176	
177	        $snapshot = json_decode((string) $versionRow->snapshot_json, true, 512, JSON_THROW_ON_ERROR);
178	        unset($snapshot['id']);
179	        $snapshot['updated_at'] = now()->utc();
180	        if ($this->hasColumn($table, 'version')) {
181	            $currentVersion = (int) DB::table($table)->where('id', $id)->value('version');
182	            $snapshot['version'] = $currentVersion + 1;
183	        }
184	
185	        DB::table($table)->where('id', $id)->update($snapshot);
186	        $updated = (array) DB::table($table)->where('id', $id)->first();
187	
188	        $this->versioning->snapshot($entity, $id, (int) ($updated['version'] ?? $targetVersion), $updated, $user->id, 'revert');
189	        $this->auditLogger->log($request, 'master_data', 'revert', 'success', $user, ['entity' => $entity, 'id' => $id, 'version' => $targetVersion]);
190	
191	        return response()->json(['data' => $updated]);
192	    }
