19	    public function items(Request $request): JsonResponse
20	    {
21	        $facilityId = (int) $request->query('facility_id', 0);
22	        $storeroomId = (int) $request->query('storeroom_id', 0);
23	
24	        $items = DB::table('inventory_items')->get()->map(function ($item) use ($facilityId, $storeroomId) {
25	            $ledger = DB::table('stock_ledger_entries')
26	                ->where('item_id', $item->id)
27	                ->when($facilityId > 0, fn ($q) => $q->where('facility_id', $facilityId))
28	                ->when($storeroomId > 0, fn ($q) => $q->where('storeroom_id', $storeroomId))
29	                ->get();
30	
31	            $onHand = $ledger->sum(function ($entry) {
32	                return match ($entry->movement_type) {
33	                    'inbound', 'transfer_in' => (float) $entry->qty,
34	                    default => -1 * (float) $entry->qty,
35	                };
36	            });
37	
38	            $reservationDemand = DB::table('inventory_reservation_events')
39	                ->where('item_id', $item->id)
40	                ->when($storeroomId > 0, fn ($q) => $q->where('storeroom_id', $storeroomId))
41	                ->sum(DB::raw("CASE WHEN event_type IN ('reserve', 'plan') THEN qty WHEN event_type IN ('consume', 'release') THEN -qty ELSE 0 END"));
42	
43	            $atp = $onHand - (float) $reservationDemand;
44	            $dailyUsage = max($ledger->where('movement_type', 'outbound')->sum('qty') / 30, 0);
45	            $safetyStock = $dailyUsage * (float) $item->safety_stock_days;
46	
47	            return [
48	                'id' => $item->id,
49	                'sku' => $item->sku,
50	                'name' => $item->name,
51	                'on_hand' => round($onHand, 3),
52	                'reserved' => round((float) $reservationDemand, 3),
53	                'atp' => round($atp, 3),
54	                'safety_stock' => round($safetyStock, 3),
55	                'low_stock' => $atp < $safetyStock,
56	            ];
57	        });
58	
59	        return response()->json(['data' => $items]);
60	    }
