119	    public function addStocktakeLines(Request $request, int $id): JsonResponse
120	    {
121	        $validated = $request->validate([
122	            'lines' => ['required', 'array', 'min:1'],
123	            'lines.*.item_id' => ['required', 'integer'],
124	            'lines.*.counted_qty' => ['required', 'numeric'],
125	            'lines.*.variance_reason' => ['nullable', 'string'],
126	        ]);
127	
128	        $stocktake = DB::table('stocktakes')->where('id', $id)->first();
129	        if ($stocktake === null) {
130	            return response()->json(ApiResponse::error('NOT_FOUND', 'Stocktake not found.', ApiResponse::requestId($request)), 404);
131	        }
132	
133	        $requiresApproval = false;
134	        foreach ($validated['lines'] as $line) {
135	            $systemQty = (float) DB::table('stock_ledger_entries')
136	                ->where('item_id', $line['item_id'])
137	                ->where('storeroom_id', $stocktake->storeroom_id)
138	                ->sum(DB::raw("CASE WHEN movement_type IN ('inbound', 'transfer_in') THEN qty ELSE -qty END"));
139	
140	            $counted = (float) $line['counted_qty'];
141	            $variancePct = $systemQty == 0.0 ? ($counted > 0 ? 100.0 : 0.0) : (($counted - $systemQty) / max(abs($systemQty), 0.001) * 100.0);
142	            $requiresLineApproval = abs($variancePct) > 5;
143	
144	            if ($requiresLineApproval && empty($line['variance_reason'])) {
145	                return response()->json(ApiResponse::error('VALIDATION_ERROR', 'Variance reason required when above +/-5%.', ApiResponse::requestId($request)), 422);
146	            }
147	
148	            DB::table('stocktake_lines')->insert([
149	                'stocktake_id' => $id,
150	                'item_id' => $line['item_id'],
151	                'system_qty' => $systemQty,
152	                'counted_qty' => $counted,
153	                'variance_pct' => $variancePct,
154	                'variance_reason' => $line['variance_reason'] ?? null,
155	                'requires_manager_approval' => $requiresLineApproval,
156	                'created_at' => now()->utc(),
157	                'updated_at' => now()->utc(),
158	            ]);
159	
160	            $requiresApproval = $requiresApproval || $requiresLineApproval;
161	        }
162	
163	        DB::table('stocktakes')->where('id', $id)->update([
164	            'status' => $requiresApproval ? 'pending_approval' : 'approved',
165	            'updated_at' => now()->utc(),
166	        ]);
167	
168	        return response()->json(['data' => DB::table('stocktakes')->where('id', $id)->first()]);
